const KAKAO_APP_KEY = 'df4915d1a699d9da7b0d1f49084ccb3b';   // B-2에서 복사한 값
const REFRESH_TOKEN = 'cqb2fZruY3MkcU4HUc_9rvnx9Y6ypNcKAAAAAgoNIdkAAAGctU6KhMc_xW4TVk05';  // B-6에서 저장한 값

// 1. 환율 데이터 수신
const rate = $input.first().json.conversion_rate;
if (!rate) throw new Error('환율 데이터를 받지 못했습니다.');

// 2. 전일 환율과 비교 (staticData에 저장)
const staticData = $getWorkflowStaticData('global');
const previousRate = staticData.previousRate ?? rate;
const change = parseFloat((rate - previousRate).toFixed(2));
const changePct = ((change / previousRate) * 100).toFixed(2);
const sign = change >= 0 ? '+' : '';
const arrow = change > 0 ? '📈' : change < 0 ? '📉' : '➡️';

// 3. 오늘 날짜
const today = new Date().toLocaleDateString('ko-KR', {
  timeZone: 'Asia/Seoul',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  weekday: 'short'
});

// 4. 전일 환율 업데이트
staticData.previousRate = rate;

// 5. 카카오 Access Token 갱신
// ✅ 수정: $http.request() → this.helpers.httpRequest()
const tokenRes = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://kauth.kakao.com/oauth/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=refresh_token&client_id=${KAKAO_APP_KEY}&refresh_token=${REFRESH_TOKEN}`,
});

const accessToken = tokenRes.access_token;
if (!accessToken) throw new Error('카카오 토큰 갱신 실패: ' + JSON.stringify(tokenRes));

// 새 refresh_token이 응답에 포함되면 자동 저장
if (tokenRes.refresh_token) {
  staticData.latestRefreshToken = tokenRes.refresh_token;
}

// 6. 메시지 작성 (200자 제한)
const rawText = `[환율 브리핑] ${today}\nUSD/KRW: ${rate.toLocaleString('ko-KR')}원\n${arrow} 전일比: ${sign}${change}원 (${sign}${changePct}%)\n출처: ExchangeRate-API`;

// ✅ 수정: 이모지 포함 시 .slice() 사용하면 깨짐 → spread로 글자 단위 자르기
const safeText = [...rawText].slice(0, 200).join('');

// 7. 카카오 메시지 템플릿 생성
const kakaoTemplate = JSON.stringify({
  object_type: 'text',
  text: safeText,
  link: {
    web_url: 'https://www.exchangerate-api.com',
    mobile_web_url: 'https://www.exchangerate-api.com'
  }
});

return [{ json: { accessToken, kakaoTemplate } }];
